class Solution(object):
    def maxDifference(self, s, k):
        """
        :type s: str
        :type k: int
        :rtype: int
        """
        n = len(s)
        max_diff = float('-inf')

        # Try all pairs of characters (a with odd frequency, b with even frequency)
        chars = set(s)

        for char_a in chars:
            for char_b in chars:
                if char_a == char_b:
                    continue

                # For pair (char_a, char_b), find all substrings of length >= k
                # where char_a has odd frequency and char_b has even frequency

                for start in range(n):
                    freq_a = 0
                    freq_b = 0

                    for end in range(start, n):
                        if s[end] == char_a:
                            freq_a += 1
                        elif s[end] == char_b:
                            freq_b += 1

                        length = end - start + 1
                        if length >= k:
                            # Check if valid for this pair
                            if freq_a % 2 == 1 and freq_b % 2 == 0 and freq_b > 0:
                                diff = freq_a - freq_b
                                max_diff = max(max_diff, diff)

        return max_diff
